// 'p' never escapes hotPath: not returned, not stored, not shared.
// With C2 + escape analysis, Point is scalar-replaced: x and y live in
// registers, no heap object, no GC. Run with -XX:-DoEscapeAnalysis to
// force the allocation and watch -Xlog:gc light up under load.
static long hotPath(int a, int b) {
    Point p = new Point(a, b);   // candidate for scalar replacement
    return (long) p.x * p.y;     // only the fields are ever read
}

static final class Point {
    final int x, y;
    Point(int x, int y) { this.x = x; this.y = y; }
}

// Explicit G1 with a 16 MB region and tight pause target:
//   java -XX:+UseG1GC -XX:G1HeapRegionSize=16m \
//        -XX:MaxGCPauseMillis=50 -Xlog:gc,gc+heap=info Main
//
// A sample -Xlog:gc line:
//   [1.234s][info][gc] GC(7) Pause Young (Normal)
//        (G1 Evacuation Pause) 512M->48M(1024M) 6.3ms
//   ^ before->after(total committed)   ^ pause duration
//
// 'Pause Young (Normal)'      = minor GC, Eden+Survivor evacuated
// 'Pause Young (Mixed)'       = young + some old regions
// 'Pause Full'                = whole-heap stop-the-world (bad: investigate)

// Watch every compilation decision:
//   java -XX:+PrintCompilation Main
//   ...
//   1234   3       hotMethod (28 bytes)     <- '3' = C1 (tier 3, profiled)
//   5678   4       hotMethod (28 bytes)     <- '4' = C2 (tier 4, optimized)
//   ...    %  made not entrant              <- deoptimized
//
// Force pure interpretation (no JIT) to isolate warm-up cost:
//   java -Xint Main
//
// Disable tiering, go straight to C2 (longer warm-up, peak throughput):
//   java -XX:-TieredCompilation Main

