import java.util.*;
import java.io.*;

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int q = Integer.parseInt(br.readLine().trim());
        long stackBytes = 0, heapBytes = 0;
        long stackCount = 0, heapCount = 0;
        for (int i = 0; i < q; i++) {
            StringTokenizer st = new StringTokenizer(br.readLine().trim());
            String escape = st.nextToken();
            long size = Long.parseLong(st.nextToken());
            long count = Long.parseLong(st.nextToken());
            boolean stackAllocatable = escape.equals("NONE");
            if (stackAllocatable) {
                stackBytes += size * count;
                stackCount += count;
            } else {
                heapBytes += size * count;
                heapCount += count;
            }
        }
        StringBuilder sb = new StringBuilder();
        sb.append("stack ").append(stackCount).append(' ').append(stackBytes).append('\n');
        sb.append("heap ").append(heapCount).append(' ').append(heapBytes).append('\n');
        System.out.print(sb);
    }
}

