import java.util.*;
import java.io.*;

public class Main {
    static long widthOf(String t) {
        switch (t) {
            case "boolean": case "byte": return 1;
            case "char": case "short": return 2;
            case "int": case "float": return 4;
            case "long": case "double": return 8;
            case "ref": return 4;
            default: throw new IllegalArgumentException(t);
        }
    }
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int f = Integer.parseInt(br.readLine().trim());
        long fieldBytes = 0;
        for (int i = 0; i < f; i++) {
            String t = br.readLine().trim();
            fieldBytes += widthOf(t);
        }
        long header = 12;
        long raw = header + fieldBytes;
        long padded = (raw + 7) & ~7L;
        long padding = padded - raw;
        StringBuilder sb = new StringBuilder();
        sb.append("header ").append(header).append('\n');
        sb.append("fields ").append(fieldBytes).append('\n');
        sb.append("padding ").append(padding).append('\n');
        sb.append("total ").append(padded).append('\n');
        System.out.print(sb);
    }
}

