import java.util.*;
import java.io.*;

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        long regionKb = Long.parseLong(br.readLine().trim());
        long regionBytes = regionKb * 1024;
        int n = Integer.parseInt(br.readLine().trim());
        long humongousObjs = 0, humongousRegions = 0;
        long normalObjs = 0, normalRegions = 0;
        long usedInCurrent = 0;
        boolean haveOpenRegion = false;
        for (int i = 0; i < n; i++) {
            long size = Long.parseLong(br.readLine().trim());
            if (size * 2 >= regionBytes) {
                humongousObjs++;
                long regions = (size + regionBytes - 1) / regionBytes;
                humongousRegions += regions;
            } else {
                normalObjs++;
                if (!haveOpenRegion || usedInCurrent + size > regionBytes) {
                    normalRegions++;
                    usedInCurrent = 0;
                    haveOpenRegion = true;
                }
                usedInCurrent += size;
            }
        }
        long totalRegions = humongousRegions + normalRegions;
        StringBuilder sb = new StringBuilder();
        sb.append("humongous ").append(humongousObjs).append(' ').append(humongousRegions).append('\n');
        sb.append("normal ").append(normalObjs).append(' ').append(normalRegions).append('\n');
        sb.append("regions ").append(totalRegions).append('\n');
        System.out.print(sb);
    }
}

