import java.util.*;
import java.io.*;

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        long edenKb = Long.parseLong(br.readLine().trim());
        long edenBytes = edenKb * 1024;
        int g = Integer.parseInt(br.readLine().trim());
        long used = 0, totalBytes = 0, minorGcs = 0;
        for (int i = 0; i < g; i++) {
            StringTokenizer st = new StringTokenizer(br.readLine().trim());
            long size = Long.parseLong(st.nextToken());
            long count = Long.parseLong(st.nextToken());
            for (long c = 0; c < count; c++) {
                if (used + size > edenBytes) { minorGcs++; used = 0; }
                used += size;
                totalBytes += size;
            }
        }
        StringBuilder sb = new StringBuilder();
        sb.append("allocated ").append(totalBytes).append('\n');
        sb.append("minorGC ").append(minorGcs).append('\n');
        System.out.print(sb);
    }
}

