import java.util.*;
import java.io.*;

public class Main {
    static final long C1 = 2000, C2 = 10000;
    static String level(long c) {
        if (c >= C2) return "C2";
        if (c >= C1) return "C1";
        return "INTERPRETED";
    }
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int q = Integer.parseInt(br.readLine().trim());
        LinkedHashMap<String, Long> counts = new LinkedHashMap<>();
        for (int i = 0; i < q; i++) {
            StringTokenizer st = new StringTokenizer(br.readLine().trim());
            st.nextToken();
            String name = st.nextToken();
            long inv = Long.parseLong(st.nextToken());
            counts.merge(name, inv, Long::sum);
        }
        StringBuilder sb = new StringBuilder();
        int c2count = 0;
        for (Map.Entry<String, Long> e : counts.entrySet()) {
            String lv = level(e.getValue());
            if (lv.equals("C2")) c2count++;
            sb.append(e.getKey()).append(' ').append(e.getValue()).append(' ').append(lv).append('\n');
        }
        sb.append("c2 ").append(c2count).append('\n');
        System.out.print(sb);
    }
}

